class V1ResolutionStatus(BaseModel):
    """
    ResolutionStatus is the response status that indicates if the operation
    succeeded. The response status will be stored with the
    results. The caller will continue with subsequent requests
    and the server can continue with additional packages.
    """

    description: str | None = None
    """
    A description of the error. Plugins should use proper descriptions that
    will be helpful to users or operations.
    """
    error_analysis: list[ErrorAnalysi] | None = None
    """
    The analysis of the error based on the error parsing rules
    that can provide additional context on possible fixes.
    """
    error_analysis_best_match: ResolutionStatusErrorAnalysis | None = None
    """
    The best error analysis match ordered by rule priority.
    """
    operation: str | None = None
    """
    The operation during which encountered the error.
    A Go plugin can return as operation reading go.mod file,
    a Java plugin can be reading a pom.xml. Every plugin is
    doing different operations and it should identify here
    the operation that failed. This again will help with debugging.
    """
    status_error: ResolutionStatusStatusError | None = 'STATUS_ERROR_UNSPECIFIED'
    """
    status_error is the error encountered.
    """
    target: str | None = None
    """
    The target object (path or package) where the failure happened. For package
    scans it is the package. For the workspace scans it is the target path.
    """
    target_files: dict[str, str] | None = None
    """
    The content of manifest files or the list of files based on the operation.
    """


class CategoryScore(BaseModel):
    """
    The score for one score category. The is the overall score
    for a specific category. It is computed from the score factors that
    have been created for the category. There is going to be only a single
    instance of this information for the repo per score category.

    Example:

    Category: SCORE_CATEGORY_BEST_PRACTICES

    Score: 5

    Description: This score provides an overview of how this repo does when considering security best practices.

    The value is a number in the range 1 to 10, with 10 being the best.
    """

    category: V1ScoreCategory | None = 'SCORE_CATEGORY_UNSPECIFIED'
    """
    The category for this score.
    """
